params.spec:
{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "description": "One hexagon per RDS database, ordered worst-first with CPU-saturated or low-storage databases first. States: saturated (CPU > 80%), low-storage (< 5 GB free), healthy (passing all checks), Unknown (no metric data). Toggle Color by between Status, CPU utilization, or Free Storage; metric views support Min, Max, Avg, and Last over the dashboard time range. Click any hexagon to filter the dashboard or open metrics for that database.",
  "usermeta": {
    "x_rds_hexmap": true
  },
  "padding": {
    "top": 10,
    "left": 10,
    "right": 10,
    "bottom": 15
  },
  "data": [
    {
      "name": "ts_probe",
      "url": {
        "%type%": "esql",
        "%context%": true,
        "%timefield%": "@timestamp",
        "query": "ROW round_key = CONCAT(TO_STRING(?_tstart), \"|\", TO_STRING(?_tend)), fetched_at = NOW()"
      }
    },
    {
      "name": "raw_all",
      "url": {
        "%type%": "esql",
        "%context%": true,
        "%timefield%": "@timestamp",
        "query": "SET unmapped_fields = \"nullify\";\nFROM metrics-aws.rds.otel-* | WHERE @timestamp >= ?_tstart AND @timestamp <= ?_tend\n AND DBInstanceIdentifier IS NOT NULL AND DBInstanceIdentifier != \"\"\n AND stat == \"Average\" | STATS cpu_min = MIN(`metrics.amazonaws.com/AWS/RDS/CPUUtilization`)\n WHERE `metrics.amazonaws.com/AWS/RDS/CPUUtilization` IS NOT NULL,\n cpu_max = MAX(`metrics.amazonaws.com/AWS/RDS/CPUUtilization`)\n WHERE `metrics.amazonaws.com/AWS/RDS/CPUUtilization` IS NOT NULL,\n cpu_avg = AVG(`metrics.amazonaws.com/AWS/RDS/CPUUtilization`)\n WHERE `metrics.amazonaws.com/AWS/RDS/CPUUtilization` IS NOT NULL,\n cpu_last = LAST(`metrics.amazonaws.com/AWS/RDS/CPUUtilization`, @timestamp)\n WHERE `metrics.amazonaws.com/AWS/RDS/CPUUtilization` IS NOT NULL,\n st_min = MIN(`metrics.amazonaws.com/AWS/RDS/FreeStorageSpace`)\n WHERE `metrics.amazonaws.com/AWS/RDS/FreeStorageSpace` IS NOT NULL,\n st_max = MAX(`metrics.amazonaws.com/AWS/RDS/FreeStorageSpace`)\n WHERE `metrics.amazonaws.com/AWS/RDS/FreeStorageSpace` IS NOT NULL,\n st_avg = AVG(`metrics.amazonaws.com/AWS/RDS/FreeStorageSpace`)\n WHERE `metrics.amazonaws.com/AWS/RDS/FreeStorageSpace` IS NOT NULL,\n st_last = LAST(`metrics.amazonaws.com/AWS/RDS/FreeStorageSpace`, @timestamp)\n WHERE `metrics.amazonaws.com/AWS/RDS/FreeStorageSpace` IS NOT NULL,\n last_seen = MAX(@timestamp)\n BY entity_id = DBInstanceIdentifier\n, cloud.region\n| INLINE STATS latest_global = MAX(last_seen)\n| WHERE DATE_DIFF(\"minutes\", last_seen, latest_global) <= 10\n| EVAL storage_min = st_min / 1073741824,\n storage_max = st_max / 1073741824,\n storage_avg = st_avg / 1073741824,\n storage_last = st_last / 1073741824,\n status_num = CASE(\n  cpu_last IS NULL AND st_last IS NULL, 3,\n  cpu_last > 80, 0,\n  st_last < 5368709120, 1,\n  2),\n status_label = CASE(\n  cpu_last IS NULL AND st_last IS NULL, \"Unknown\",\n  cpu_last > 80, \"saturated\",\n  st_last < 5368709120, \"low-storage\",\n  \"healthy\"),\n severity_rank = status_num,\n round_key = CONCAT(TO_STRING(?_tstart), \"|\", TO_STRING(?_tend)),\n fetched_at = NOW()\n| KEEP entity_id, status_num, status_label, severity_rank,\n cpu_min, cpu_max, cpu_avg, cpu_last,\n storage_min, storage_max, storage_avg, storage_last,\n round_key, fetched_at\n| LIMIT 10000"
      }
    },
    {
      "name": "ranked_status",
      "source": "raw_all",
      "transform": [
        {
          "type": "collect",
          "sort": {
            "field": [
              "severity_rank",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_min",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_min == null ? 1e12 : -datum.cpu_min * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_max",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_max == null ? 1e12 : -datum.cpu_max * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_avg",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_avg == null ? 1e12 : -datum.cpu_avg * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_cpu_last",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.cpu_last == null ? 1e12 : -datum.cpu_last * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_storage_min",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.storage_min == null ? 1e12 : datum.storage_min * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_storage_max",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.storage_max == null ? 1e12 : datum.storage_max * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_storage_avg",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.storage_avg == null ? 1e12 : datum.storage_avg * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "ranked_storage_last",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "sort_key",
          "expr": "datum.storage_last == null ? 1e12 : datum.storage_last * 1000000"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "sort_key",
              "entity_id"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "active_rank"
          ]
        }
      ]
    },
    {
      "name": "active",
      "values": [],
      "on": [
        {
          "trigger": "ts_round !== '' && active_round !== '' && active_round !== ts_round",
          "remove": "true"
        },
        {
          "trigger": "metric === 'status' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_status')"
        },
        {
          "trigger": "metric === 'cpu' && effective_agg === 'min' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_min')"
        },
        {
          "trigger": "metric === 'cpu' && effective_agg === 'max' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_max')"
        },
        {
          "trigger": "metric === 'cpu' && effective_agg === 'avg' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_avg')"
        },
        {
          "trigger": "metric === 'cpu' && effective_agg === 'last' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_cpu_last')"
        },
        {
          "trigger": "metric === 'storage' && effective_agg === 'min' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_storage_min')"
        },
        {
          "trigger": "metric === 'storage' && effective_agg === 'max' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_storage_max')"
        },
        {
          "trigger": "metric === 'storage' && effective_agg === 'avg' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_storage_avg')"
        },
        {
          "trigger": "metric === 'storage' && effective_agg === 'last' && len_raw > 0 && raw_round === ts_round && ts_round !== ''",
          "remove": "true",
          "insert": "data('ranked_storage_last')"
        }
      ]
    },
    {
      "name": "entities",
      "source": "active",
      "transform": [
        {
          "type": "formula",
          "as": "active_val",
          "expr": "metric=='status' ? null : (metric=='cpu' ? (effective_agg=='min' ? datum.cpu_min : effective_agg=='max' ? datum.cpu_max : effective_agg=='avg' ? datum.cpu_avg : effective_agg=='last' ? datum.cpu_last : null) : (metric=='storage' ? (effective_agg=='min' ? datum.storage_min : effective_agg=='max' ? datum.storage_max : effective_agg=='avg' ? datum.storage_avg : effective_agg=='last' ? datum.storage_last : null) : null))"
        },
        {
          "type": "formula",
          "as": "index0",
          "expr": "datum.active_rank - 1"
        },
        {
          "type": "formula",
          "as": "col",
          "expr": "datum.index0 % gridCols"
        },
        {
          "type": "formula",
          "as": "row",
          "expr": "floor(datum.index0 / gridCols)"
        },
        {
          "type": "formula",
          "as": "x",
          "expr": "datum.col * gapX + (datum.row % 2 == 1 ? gapX / 2 : 0) + hexR + 5"
        },
        {
          "type": "formula",
          "as": "y",
          "expr": "datum.row * gapY + hexR + 5 + hexOffsetY"
        },
        {
          "type": "formula",
          "as": "hexSize",
          "expr": "hexR * hexR * 3.46"
        }
      ]
    },
    {
      "name": "status_counts",
      "source": "raw_all",
      "transform": [
        {
          "type": "aggregate",
          "groupby": [
            "status_num"
          ],
          "ops": [
            "count"
          ],
          "as": [
            "count"
          ]
        }
      ]
    },
    {
      "name": "status_legend",
      "values": [
        {
          "label": "Saturated",
          "val": 0
        },
        {
          "label": "Low storage",
          "val": 1
        },
        {
          "label": "Healthy",
          "val": 2
        },
        {
          "label": "Unknown",
          "val": 3
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "status_counts",
          "key": "status_num",
          "fields": [
            "val"
          ],
          "values": [
            "count"
          ],
          "as": [
            "count"
          ],
          "default": 0
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "idx"
          ]
        }
      ]
    },
    {
      "name": "cpu_counts",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "v",
          "expr": "agg == 'min' ? datum.cpu_min : agg == 'max' ? datum.cpu_max : agg == 'avg' ? datum.cpu_avg : agg == 'last' ? datum.cpu_last : null"
        },
        {
          "type": "formula",
          "as": "bucket",
          "expr": "datum.v == null ? 3 : (datum.v >= 80 ? 2 : datum.v >= 60 ? 1 : 0)"
        },
        {
          "type": "aggregate",
          "groupby": [
            "bucket"
          ],
          "ops": [
            "count"
          ],
          "as": [
            "count"
          ]
        }
      ]
    },
    {
      "name": "storage_counts",
      "source": "raw_all",
      "transform": [
        {
          "type": "formula",
          "as": "v",
          "expr": "agg == 'min' ? datum.storage_min : agg == 'max' ? datum.storage_max : agg == 'avg' ? datum.storage_avg : agg == 'last' ? datum.storage_last : null"
        },
        {
          "type": "formula",
          "as": "bucket",
          "expr": "datum.v == null ? 3 : (datum.v >= 20 ? 2 : datum.v >= 5 ? 1 : 0)"
        },
        {
          "type": "aggregate",
          "groupby": [
            "bucket"
          ],
          "ops": [
            "count"
          ],
          "as": [
            "count"
          ]
        }
      ]
    },
    {
      "name": "cpu_legend_stops",
      "values": [
        {
          "label": "≥ 80%",
          "val": 90,
          "bucket": 2,
          "is_nodata": false
        },
        {
          "label": "60 – 79%",
          "val": 70,
          "bucket": 1,
          "is_nodata": false
        },
        {
          "label": "< 60%",
          "val": 0,
          "bucket": 0,
          "is_nodata": false
        },
        {
          "label": "Unknown",
          "val": null,
          "bucket": 3,
          "is_nodata": true
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "cpu_counts",
          "key": "bucket",
          "fields": [
            "bucket"
          ],
          "values": [
            "count"
          ],
          "as": [
            "count"
          ],
          "default": 0
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "idx"
          ]
        }
      ]
    },
    {
      "name": "storage_legend_stops",
      "values": [
        {
          "label": "< 5 GB",
          "val": 2,
          "bucket": 0,
          "is_nodata": false
        },
        {
          "label": "5 – 19 GB",
          "val": 10,
          "bucket": 1,
          "is_nodata": false
        },
        {
          "label": "≥ 20 GB",
          "val": 50,
          "bucket": 2,
          "is_nodata": false
        },
        {
          "label": "Unknown",
          "val": null,
          "bucket": 3,
          "is_nodata": true
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "storage_counts",
          "key": "bucket",
          "fields": [
            "bucket"
          ],
          "values": [
            "count"
          ],
          "as": [
            "count"
          ],
          "default": 0
        },
        {
          "type": "window",
          "ops": [
            "row_number"
          ],
          "as": [
            "idx"
          ]
        }
      ]
    },
    {
      "name": "spinner_dots",
      "values": [
        {
          "i": 0
        },
        {
          "i": 1
        },
        {
          "i": 2
        },
        {
          "i": 3
        },
        {
          "i": 4
        },
        {
          "i": 5
        },
        {
          "i": 6
        },
        {
          "i": 7
        }
      ]
    },
    {
      "name": "pills",
      "values": [
        {
          "id": "status",
          "label": "Status",
          "group": "metric",
          "x": 69,
          "w": 48,
          "available_aggs": [],
          "default_agg": "last"
        },
        {
          "id": "cpu",
          "label": "CPU %",
          "group": "metric",
          "x": 125,
          "w": 58,
          "available_aggs": [
            "min",
            "max",
            "avg",
            "last"
          ],
          "default_agg": "last"
        },
        {
          "id": "storage",
          "label": "Free Storage (GB)",
          "group": "metric",
          "x": 191,
          "w": 128,
          "available_aggs": [
            "min",
            "max",
            "avg",
            "last"
          ],
          "default_agg": "last"
        },
        {
          "id": "min",
          "label": "Min",
          "group": "agg",
          "x": 425,
          "w": 36,
          "valid_for": [
            "cpu",
            "storage"
          ]
        },
        {
          "id": "max",
          "label": "Max",
          "group": "agg",
          "x": 465,
          "w": 36,
          "valid_for": [
            "cpu",
            "storage"
          ]
        },
        {
          "id": "avg",
          "label": "Avg",
          "group": "agg",
          "x": 505,
          "w": 36,
          "valid_for": [
            "cpu",
            "storage"
          ]
        },
        {
          "id": "last",
          "label": "Last",
          "group": "agg",
          "x": 545,
          "w": 40,
          "valid_for": [
            "cpu",
            "storage"
          ]
        },
        {
          "id": "sum",
          "label": "Sum",
          "group": "agg",
          "x": 589,
          "w": 40,
          "valid_for": []
        }
      ]
    },
    {
      "name": "menu_items_data",
      "values": [
        {
          "id": "filter",
          "label": "Filter dashboard by this database",
          "idx": 0
        },
        {
          "id": "metrics",
          "label": "View database metrics in Discover",
          "idx": 1
        }
      ]
    },
    {
      "name": "menu_visible",
      "values": [
        {
          "_": 0
        }
      ],
      "transform": [
        {
          "type": "filter",
          "expr": "selected_entity != null"
        }
      ]
    },
    {
      "name": "menu_items_visible",
      "source": "menu_items_data",
      "transform": [
        {
          "type": "filter",
          "expr": "selected_entity != null"
        }
      ]
    }
  ],
  "signals": [
    {
      "name": "metric",
      "value": "status",
      "on": [
        {
          "events": "@pill_bg:click",
          "update": "datum.group === 'metric' ? datum.id : metric"
        }
      ]
    },
    {
      "name": "agg",
      "value": "last",
      "on": [
        {
          "events": "@pill_bg:click",
          "update": "datum.group === 'agg' && metric !== 'status' && indexof(datum.valid_for, metric) >= 0 ? datum.id : ( datum.group === 'metric' && datum.id !== 'status' ? (indexof(datum.available_aggs, agg) >= 0 ? agg : datum.default_agg) : agg )"
        }
      ]
    },
    {
      "name": "effective_agg",
      "update": "metric === 'cpu' ? ((agg === 'min' || agg === 'max' || agg === 'avg' || agg === 'last') ? agg : 'last') : metric === 'storage' ? ((agg === 'min' || agg === 'max' || agg === 'avg' || agg === 'last') ? agg : 'last') : 'last'"
    },
    {
      "name": "groupHeaderH",
      "value": 20
    },
    {
      "name": "groupGap",
      "value": 10
    },
    {
      "name": "group_by",
      "value": "none"
    },
    {
      "name": "len_raw",
      "update": "length(data('raw_all'))"
    },
    {
      "name": "len_active",
      "update": "length(data('active'))"
    },
    {
      "name": "ts_round",
      "update": "data('ts_probe')[0] ? data('ts_probe')[0].round_key : ''"
    },
    {
      "name": "time_from",
      "update": "ts_round !== '' && indexof(ts_round, '|') > 0 ? slice(ts_round, 0, indexof(ts_round, '|')) : ''"
    },
    {
      "name": "time_to",
      "update": "ts_round !== '' && indexof(ts_round, '|') > 0 ? slice(ts_round, indexof(ts_round, '|') + 1) : ''"
    },
    {
      "name": "g_param",
      "update": "time_from !== '' && time_to !== '' ? '_g=(time:(from:%27' + time_from + '%27,to:%27' + time_to + '%27))&' : ''"
    },
    {
      "name": "raw_round",
      "update": "data('raw_all')[0] ? data('raw_all')[0].round_key : ''"
    },
    {
      "name": "active_round",
      "update": "raw_round"
    },
    {
      "name": "raw_fetched_str",
      "update": "data('raw_all')[0] ? data('raw_all')[0].fetched_at : ''"
    },
    {
